import React, { useState } from "react";
import {
  AreaChart, Area, BarChart, Bar, RadialBarChart, RadialBar,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell
} from "recharts";
import { usePlantData }          from "../hooks/usePlantData";
import { MetricCard }            from "../components/MetricCard";
import { ModulePanel }           from "../components/ModulePanel";
import { RiskBadge, RISK_COLOR } from "../components/RiskBadge";
import { ChatPanel }             from "../components/ChatPanel";
import { LoadingScreen, ErrorScreen } from "../components/StatusScreens";

const TT = { background: "#0d1526", border: "1px solid #1a2844", color: "#d8e8f4", fontSize: 11 };
const TX = { fill: "#3d5a80", fontSize: 10 };

const TABS = ["overview", "energy", "anomalies", "maintenance", "failure", "chat"];

function Svg({ d, size = 14, color = "currentColor" }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none"
      stroke={color} strokeWidth="1.8" strokeLinecap="round" strokeLinejoin="round">
      <path d={d} />
    </svg>
  );
}
const PLANT_D   = "M3 9l9-7 9 7v11a2 2 0 01-2 2H5a2 2 0 01-2-2z";
const ALERT_D   = "M12 22c1 0 2-1 2-2H10c0 1 1 2 2 2zm6-6v-5c0-3.07-1.63-5.64-4.5-6.32V4a1.5 1.5 0 00-3 0v.68C7.64 5.36 6 7.92 6 11v5l-2 2v1h16v-1l-2-2z";
const REFRESH_D = "M23 4v6h-6M1 20v-6h6M3.51 9a9 9 0 0114.85-3.36L23 10M1 14l4.64 4.36A9 9 0 0020.49 15";

export default function Dashboard() {
  const { snap, report, anomalies, maintenance, failures, loading, error, lastRefresh, refresh } = usePlantData();
  const [tab, setTab] = useState("overview");

  if (loading) return <LoadingScreen />;
  if (error)   return <ErrorScreen message={error} onRetry={refresh} />;

  const f  = report.forecasting;
  const d  = report.demand;
  const e  = report.energy;
  const a  = report.anomaly;
  const pb = report.plant_behavior;
  const m  = report.maintenance;
  const fl = report.failure;

  const forecastData = (f.forecast_10_steps?.temperature || []).map((v, i) => ({
    step: `+${i + 1}`,
    temperature: v,
    pressure:  (f.forecast_10_steps?.pressure || [])[i],
    power_kw:  (f.forecast_10_steps?.power_kw  || [])[i],
  }));

  const energyData = Object.entries(e.by_equipment || {}).map(([eq, v]) => ({
    name: eq, kw: v.avg_kw, peak: v.peak_kw, eff: Math.round(v.efficiency_pct)
  }));

  const behaviorData = Object.entries(pb.behavior_distribution || {}).map(([k, v]) => ({
    name: k, value: parseFloat(v), fill: RISK_COLOR[k] || "#a0aec0"
  }));

  const maintData = Object.entries(m.by_equipment || {}).map(([eq, v]) => ({
    name: eq, rul: v.min_rul_hrs, risk: v.dominant_risk
  }));

  const healthData = Object.entries(fl.fleet_health || {}).map(([k, v]) => ({
    name: k, value: parseFloat(v), fill: RISK_COLOR[k] || "#a0aec0"
  }));

  const imm = fl.imminent_failures || 0;

  return (
    <div className="dashboard">

      {/* HEADER */}
      <header className="dash-header">
        <div className="header-left">
          <span className="header-logo">ARIA</span>
          <div className="header-divider" />
          <span className="header-plant"><Svg d={PLANT_D} size={13} /> {snap.plant_id} / {snap.equipment_id}</span>
        </div>
        <nav className="dash-nav">
          {TABS.map(t => (
            <button key={t} className={`nav-btn ${tab === t ? "active" : ""}`} onClick={() => setTab(t)}>
              {t.toUpperCase()}
            </button>
          ))}
        </nav>
        <div className="header-meta">
          <button className="icon-btn" onClick={refresh} title="Refresh"><Svg d={REFRESH_D} size={13} /></button>
          <span className="live-pill"><span className="live-dot" />LIVE</span>
          {lastRefresh && <span className="header-time">{lastRefresh.toLocaleTimeString()}</span>}
        </div>
      </header>

      {/* ALERT BANNER */}
      {imm > 0 && (
        <div className="alert-banner">
          <Svg d={ALERT_D} size={14} color="#ff3b5c" />
          <strong>{imm} unit(s)</strong>&nbsp;flagged IMMINENT failure —
          avg probability {(fl.avg_failure_probability * 100).toFixed(1)}%.
          &nbsp;<span className="banner-equip">{Object.keys(fl.critical_equipment || {}).slice(0, 3).join(" · ")}</span>
        </div>
      )}

      <main className="dash-main">

        {/* ─── OVERVIEW ─── */}
        {tab === "overview" && (
          <div className="tab-content">
            <div className="kpi-strip">
              <MetricCard label="Temperature"   value={snap.temperature.toFixed(1)} unit="°C"   accent="#ff8c42" />
              <MetricCard label="Pressure"      value={snap.pressure.toFixed(1)}    unit=" bar"  accent="#4facfe" />
              <MetricCard label="Vibration"     value={snap.vibration.toFixed(4)}   unit=" g"    accent="#ffd166" />
              <MetricCard label="Power Draw"    value={snap.power_kw.toFixed(1)}    unit=" kW"   accent="#a78bfa" />
              <MetricCard label="Anomaly Rate"  value={a.anomaly_rate_pct}          unit="%"     accent="#ff3b5c" sub={`${a.total_anomalies} events`} />
              <MetricCard label="Avg RUL"       value={m.avg_rul_hours}             unit=" hrs"  accent="#06d6a0" sub="remaining useful life" />
              <MetricCard label="Fleet Healthy" value={fl.fleet_health?.HEALTHY}   unit="%"     accent="#06d6a0" sub={`${imm} imminent`} />
              <MetricCard label="Demand MAE"    value={d.mean_absolute_error_pct}  unit="%"     accent="#ffd166" sub="forecast error" />
            </div>

            <div className="grid-2-1">
              <ModulePanel title="Sensor Forecast — Next 10 Steps" iconKey="forecast" accent="#4facfe">
                <ResponsiveContainer width="100%" height={210}>
                  <AreaChart data={forecastData} margin={{ top: 4, right: 8, bottom: 0, left: -10 }}>
                    <defs>
                      <linearGradient id="gt" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%"  stopColor="#ff8c42" stopOpacity={0.35}/><stop offset="95%" stopColor="#ff8c42" stopOpacity={0}/>
                      </linearGradient>
                      <linearGradient id="gp" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%"  stopColor="#4facfe" stopOpacity={0.3}/><stop offset="95%" stopColor="#4facfe" stopOpacity={0}/>
                      </linearGradient>
                      <linearGradient id="gk" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%"  stopColor="#a78bfa" stopOpacity={0.3}/><stop offset="95%" stopColor="#a78bfa" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid strokeDasharray="3 3" stroke="#1a2844" />
                    <XAxis dataKey="step" tick={TX} />
                    <YAxis tick={TX} />
                    <Tooltip contentStyle={TT} />
                    <Area type="monotone" dataKey="temperature" name="Temp °C"      stroke="#ff8c42" fill="url(#gt)" strokeWidth={2} dot={false} />
                    <Area type="monotone" dataKey="pressure"    name="Pressure bar" stroke="#4facfe" fill="url(#gp)" strokeWidth={2} dot={false} />
                    <Area type="monotone" dataKey="power_kw"    name="Power kW"     stroke="#a78bfa" fill="url(#gk)" strokeWidth={2} dot={false} />
                  </AreaChart>
                </ResponsiveContainer>
                <div className="trend-chips">
                  {Object.entries(f.trend || {}).map(([k, v]) => (
                    <span key={k} className={`trend-chip ${v}`}>{k}: {v}</span>
                  ))}
                </div>
              </ModulePanel>

              <ModulePanel title="Plant Behavior" iconKey="behavior" accent="#a78bfa" badge={`${pb.critical_events} critical`}>
                <ResponsiveContainer width="100%" height={170}>
                  <RadialBarChart innerRadius="25%" outerRadius="90%" data={behaviorData} startAngle={180} endAngle={0}>
                    <RadialBar dataKey="value" label={{ position: "insideStart", fill: "#070c18", fontSize: 9, fontWeight: 600 }} />
                    <Tooltip contentStyle={TT} />
                  </RadialBarChart>
                </ResponsiveContainer>
                <div className="legend-list">
                  {behaviorData.map(b => (
                    <span key={b.name} className="legend-item">
                      <span className="legend-dot" style={{ background: b.fill }} />
                      {b.name} <span className="dimtext">{b.value}%</span>
                    </span>
                  ))}
                </div>
              </ModulePanel>
            </div>

            <div className="grid-2">
              <ModulePanel title="Demand Prediction by Product" iconKey="demand" accent="#ffd166">
                <div className="product-grid">
                  {Object.entries(d.by_product || {}).map(([prod, v]) => (
                    <div key={prod} className="product-row">
                      <span className="prod-name">{prod}</span>
                      <span className="prod-val">{v.avg_forecast.toLocaleString()} <span className="dimtext">forecast</span></span>
                      <span className="prod-val">{v.avg_actual.toLocaleString()} <span className="dimtext">actual</span></span>
                      <span className={`stockout-tag ${v.stockout_risk_pct > 30 ? "hi" : "lo"}`}>{v.stockout_risk_pct}% stockout</span>
                    </div>
                  ))}
                </div>
              </ModulePanel>

              <ModulePanel title="Remaining Useful Life by Equipment" iconKey="maintenance" accent="#06d6a0">
                <ResponsiveContainer width="100%" height={190}>
                  <BarChart data={maintData} layout="vertical" margin={{ top: 0, right: 8, bottom: 0, left: 10 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#1a2844" />
                    <XAxis type="number" tick={TX} />
                    <YAxis dataKey="name" type="category" tick={TX} width={64} />
                    <Tooltip contentStyle={TT} />
                    <Bar dataKey="rul" name="Min RUL (hrs)" radius={[0, 4, 4, 0]}>
                      {maintData.map((entry, i) => <Cell key={i} fill={RISK_COLOR[entry.risk] || "#06d6a0"} />)}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </ModulePanel>
            </div>

            <div className="log-banner">
              <Svg d={ALERT_D} size={14} color={snap.log_severity === "HIGH" ? "#ff3b5c" : "#ffd166"} />
              <span className="log-eq">{snap.equipment_id}</span>
              <span className="log-text">{snap.last_log}</span>
              <RiskBadge label={snap.log_severity} />
            </div>
          </div>
        )}

        {/* ─── ENERGY ─── */}
        {tab === "energy" && (
          <div className="tab-content">
            <div className="kpi-strip">
              <MetricCard label="Total Energy"    value={e.total_energy_kwh}     unit=" kWh" accent="#a78bfa" />
              <MetricCard label="Carbon Emission" value={e.carbon_emission_kg}   unit=" kg"  accent="#ff3b5c" sub="CO₂ equivalent" />
              <MetricCard label="Energy Cost"     value={`₹${e.energy_cost_INR}`}             accent="#ffd166" />
              <MetricCard label="Avg Power Draw"  value={e.avg_predicted_kw}     unit=" kW"  accent="#4facfe" />
              <MetricCard label="Avg Waste"       value={e.avg_waste_kw}         unit=" kW"  accent="#ff8c42" sub="above baseline" />
            </div>
            <ModulePanel title="Power Consumption by Equipment" iconKey="energy" accent="#a78bfa">
              <ResponsiveContainer width="100%" height={300}>
                <BarChart data={energyData} margin={{ top: 4, right: 12, bottom: 0, left: -10 }}>
                  <CartesianGrid strokeDasharray="3 3" stroke="#1a2844" />
                  <XAxis dataKey="name" tick={TX} />
                  <YAxis tick={TX} />
                  <Tooltip contentStyle={TT} />
                  <Bar dataKey="kw"   name="Avg kW"       fill="#a78bfa" radius={[4,4,0,0]} />
                  <Bar dataKey="peak" name="Peak kW"      fill="#ff8c42" radius={[4,4,0,0]} />
                  <Bar dataKey="eff"  name="Efficiency %" fill="#06d6a0" radius={[4,4,0,0]} />
                </BarChart>
              </ResponsiveContainer>
            </ModulePanel>
            <div className="equip-grid">
              {Object.entries(e.by_equipment || {}).map(([eq, v]) => {
                const c = v.efficiency_pct >= 90 ? "#06d6a0" : v.efficiency_pct >= 75 ? "#ffd166" : "#ff3b5c";
                return (
                  <div key={eq} className="equip-card" style={{ "--accent": c }}>
                    <span className="equip-name">{eq}</span>
                    <span className="equip-val">{v.avg_kw} kW avg / {v.peak_kw} kW peak</span>
                    <div className="equip-meta">
                      <span className="equip-rate">Efficiency</span>
                      <span style={{ color: c, fontWeight: 500 }}>{v.efficiency_pct}%</span>
                    </div>
                    <div className="equip-bar"><div className="equip-fill" style={{ width: `${Math.min(v.efficiency_pct, 100)}%` }} /></div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* ─── ANOMALIES ─── */}
        {tab === "anomalies" && (
          <div className="tab-content">
            <div className="kpi-strip">
              <MetricCard label="Total Anomalies" value={a.total_anomalies}    accent="#ff3b5c" />
              <MetricCard label="Anomaly Rate"    value={a.anomaly_rate_pct} unit="%" accent="#ff8c42" sub="of all readings" />
              {Object.entries(a.by_equipment || {}).sort((x, y) => y[1].anomaly_rate_pct - x[1].anomaly_rate_pct).slice(0, 3).map(([eq, v]) => (
                <MetricCard key={eq} label={eq} value={v.anomaly_rate_pct} unit="%" accent={v.anomaly_rate_pct > 20 ? "#ff3b5c" : "#ffd166"} sub={`${v.anomaly_count} events`} />
              ))}
            </div>
            <div className="grid-2">
              <ModulePanel title="Anomaly Events — Latest 20" iconKey="anomaly" accent="#ff3b5c">
                <div className="data-table">
                  <div className="table-head" style={{ gridTemplateColumns: "90px 80px 70px 70px 75px 75px 80px" }}>
                    <span>Time</span><span>Equipment</span><span>Plant</span><span>Temp</span><span>Pressure</span><span>Vibration</span><span>Score</span>
                  </div>
                  {anomalies.map((row, i) => (
                    <div key={i} className="table-row" style={{ gridTemplateColumns: "90px 80px 70px 70px 75px 75px 80px" }}>
                      <span className="dimtext">{new Date(row.timestamp).toLocaleTimeString()}</span>
                      <span>{row.equipment_id}</span>
                      <span className="dimtext">{row.plant_id}</span>
                      <span className={row.temperature > 120 ? "val-warn" : ""}>{row.temperature}</span>
                      <span className={row.pressure > 180 ? "val-warn" : ""}>{row.pressure}</span>
                      <span className={row.vibration > 0.06 ? "val-warn" : ""}>{row.vibration}</span>
                      <span className="val-red">{row.anomaly_score?.toFixed(4)}</span>
                    </div>
                  ))}
                </div>
              </ModulePanel>
              <ModulePanel title="Anomaly Rate by Equipment" iconKey="anomaly" accent="#ff8c42">
                <div className="equip-grid single-col">
                  {Object.entries(a.by_equipment || {}).sort((x, y) => y[1].anomaly_rate_pct - x[1].anomaly_rate_pct).map(([eq, v]) => {
                    const c = v.anomaly_rate_pct > 20 ? "#ff3b5c" : v.anomaly_rate_pct > 10 ? "#ff8c42" : "#06d6a0";
                    return (
                      <div key={eq} className="equip-card" style={{ "--accent": c }}>
                        <span className="equip-name">{eq}</span>
                        <div className="equip-meta"><span className="equip-rate">{v.anomaly_count} events</span><span style={{ color: c }}>{v.anomaly_rate_pct}%</span></div>
                        <div className="equip-bar"><div className="equip-fill" style={{ width: `${Math.min(v.anomaly_rate_pct * 4, 100)}%` }} /></div>
                      </div>
                    );
                  })}
                </div>
              </ModulePanel>
            </div>
          </div>
        )}

        {/* ─── MAINTENANCE ─── */}
        {tab === "maintenance" && (
          <div className="tab-content">
            <div className="kpi-strip">
              <MetricCard label="Avg RUL"  value={m.avg_rul_hours} unit=" hrs" accent="#06d6a0" sub="remaining useful life" />
              <MetricCard label="Critical" value={m.risk_distribution?.CRITICAL || 0} accent="#ff3b5c" />
              <MetricCard label="High"     value={m.risk_distribution?.HIGH || 0}     accent="#ff8c42" />
              <MetricCard label="Medium"   value={m.risk_distribution?.MEDIUM || 0}   accent="#ffd166" />
              <MetricCard label="Low"      value={m.risk_distribution?.LOW || 0}      accent="#06d6a0" />
            </div>
            {m.equipment_needing_attention?.length > 0 && (
              <ModulePanel title="Immediate Attention Required" iconKey="alert" accent="#ff3b5c" badge="URGENT">
                <div className="attention-list">
                  {m.equipment_needing_attention.map((eq, i) => (
                    <div key={i} className="attention-row">
                      <Svg d={ALERT_D} size={14} color="#ff3b5c" />
                      <span className="attention-eq">{eq.equipment_id}</span>
                      <div className="attention-bar">
                        <div className="attention-fill" style={{ width: `${Math.max(5, 100 - (eq.min_rul / 600) * 100)}%` }} />
                      </div>
                      <span className="val-red">{eq.min_rul} hrs RUL</span>
                    </div>
                  ))}
                </div>
              </ModulePanel>
            )}
            <ModulePanel title="Maintenance Feed — Live" iconKey="maintenance" accent="#06d6a0">
              <div className="data-table">
                <div className="table-head" style={{ gridTemplateColumns: "90px 90px 80px 100px 110px" }}>
                  <span>Time</span><span>Equipment</span><span>Plant</span><span>RUL (hrs)</span><span>Risk Level</span>
                </div>
                {maintenance.map((row, i) => (
                  <div key={i} className="table-row" style={{ gridTemplateColumns: "90px 90px 80px 100px 110px" }}>
                    <span className="dimtext">{new Date(row.timestamp).toLocaleTimeString()}</span>
                    <span>{row.equipment_id}</span>
                    <span className="dimtext">{row.plant_id}</span>
                    <span className={row.rul_hours < 100 ? "val-red" : row.rul_hours < 250 ? "val-warn" : ""}>{row.rul_hours}</span>
                    <span><RiskBadge label={row.risk_level} /></span>
                  </div>
                ))}
              </div>
            </ModulePanel>
            <div className="equip-grid">
              {Object.entries(m.by_equipment || {}).map(([eq, v]) => (
                <div key={eq} className="equip-card" style={{ "--accent": RISK_COLOR[v.dominant_risk] || "#06d6a0" }}>
                  <span className="equip-name">{eq}</span>
                  <RiskBadge label={v.dominant_risk} />
                  <span className="equip-val" style={{ marginTop: 8 }}>Min RUL: {v.min_rul_hrs} hrs</span>
                  <span className="equip-val">Avg RUL: {v.avg_rul_hrs} hrs</span>
                  <div className="equip-bar" style={{ marginTop: 8 }}>
                    <div className="equip-fill" style={{ width: `${Math.min((v.avg_rul_hrs / 600) * 100, 100)}%` }} />
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* ─── FAILURE PREDICTION ─── */}
        {tab === "failure" && (
          <div className="tab-content">
            <div className="kpi-strip">
              <MetricCard label="Imminent"         value={fl.imminent_failures}                                            accent="#ff3b5c" sub="< 24 hrs" />
              <MetricCard label="Avg Fail Prob"    value={(fl.avg_failure_probability * 100).toFixed(1)} unit="%" accent="#ff8c42" />
              <MetricCard label="Fleet Healthy"    value={fl.fleet_health?.HEALTHY}         unit="%"    accent="#06d6a0" />
              <MetricCard label="High Risk"        value={fl.fleet_health?.HIGH_RISK}        unit="%"    accent="#ff8c42" />
              <MetricCard label="Severity Logs"    value={fl.maintenance_logs_high_severity}             accent="#ffd166" sub="HIGH severity" />
            </div>
            <div className="grid-2">
              <ModulePanel title="Fleet Health Distribution" iconKey="failure" accent="#ff3b5c">
                <ResponsiveContainer width="100%" height={240}>
                  <BarChart data={healthData} margin={{ top: 4, right: 8, bottom: 0, left: -10 }}>
                    <CartesianGrid strokeDasharray="3 3" stroke="#1a2844" />
                    <XAxis dataKey="name" tick={TX} />
                    <YAxis tick={TX} unit="%" />
                    <Tooltip contentStyle={TT} formatter={v => [`${v}%`]} />
                    <Bar dataKey="value" name="Fleet %" radius={[4,4,0,0]}>
                      {healthData.map((entry, i) => <Cell key={i} fill={entry.fill} />)}
                    </Bar>
                  </BarChart>
                </ResponsiveContainer>
              </ModulePanel>
              <ModulePanel title="Critical Equipment — Failure Probability" iconKey="failure" accent="#ff8c42">
                <div className="critical-list">
                  {Object.entries(fl.critical_equipment || {}).map(([eq, prob]) => (
                    <div key={eq} className="critical-row">
                      <span className="critical-eq">{eq}</span>
                      <div className="prob-bar">
                        <div className="prob-fill" style={{ width: `${Math.min(prob * 100, 100)}%`, background: prob > 0.75 ? "#ff3b5c" : "#ff8c42" }} />
                      </div>
                      <span className="prob-val val-red">{(prob * 100).toFixed(1)}%</span>
                    </div>
                  ))}
                </div>
              </ModulePanel>
            </div>
            <ModulePanel title="Equipment Failure Predictions — Live" iconKey="failure" accent="#ff3b5c">
              <div className="data-table">
                <div className="table-head" style={{ gridTemplateColumns: "90px 90px 80px 110px 100px 110px" }}>
                  <span>Time</span><span>Equipment</span><span>Plant</span><span>Status</span><span>Probability</span><span>Horizon</span>
                </div>
                {failures.map((row, i) => (
                  <div key={i} className="table-row" style={{ gridTemplateColumns: "90px 90px 80px 110px 100px 110px" }}>
                    <span className="dimtext">{new Date(row.timestamp).toLocaleTimeString()}</span>
                    <span>{row.equipment_id}</span>
                    <span className="dimtext">{row.plant_id}</span>
                    <span><RiskBadge label={row.failure_label} /></span>
                    <span className={row.failure_prob > 0.6 ? "val-red" : row.failure_prob > 0.35 ? "val-warn" : ""}>
                      {(row.failure_prob * 100).toFixed(1)}%
                    </span>
                    <span className="dimtext">{row.failure_horizon}</span>
                  </div>
                ))}
              </div>
            </ModulePanel>
          </div>
        )}

        {/* ─── CHAT ─── */}
        {tab === "chat" && (
          <div className="tab-content chat-tab">
            <ChatPanel />
          </div>
        )}

      </main>
    </div>
  );
}
